parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "isReply": {
      "type": "boolean",
      "description": "Whether the email requires a reply"
    },
    "response": {
      "type": "string",
      "description": "The drafted reply text if isReply is true, otherwise empty"
    }
  },
  "required": ["isReply", "response"]
}
